from itertools import islice


def sliding_window(sequence, width):
    """Return a sliding window (of width n) over data from the iterable

    >>> a = sliding_window([0, 1, 2, 3], 2)
    >>> next(a)
    (0, 1)
    >>> next(a)
    (1, 2)
    >>> next(a)
    (2, 3)
    """
    iterator = iter(sequence)
    result = tuple(islice(iterator, width))
    if len(result) == width:
        yield result
    for element in iterator:
        result = result[1:] + (element,)
        yield result


def diverging(sequence, index):
    """Yield the elements of sequence, starting by the one located at "index",
    and then the ones that are increasingly far. The indices are wrapping.

    >>> n = diverging([0, 1, 2, 3], 2)
    >>> next(n)
    2
    >>> next(n)
    3
    >>> next(n)
    1
    >>> next(n)
    0
    """
    for count in range(1, len(sequence) + 1):
        distance = count // 2
        direction = 1 - 2 * (count % 2)
        yield sequence[(index + distance * direction) % len(sequence)]
